using ModelContextProtocol.Server;
using System.ComponentModel;

[McpServerToolType]
public static class Tools
{
    [McpServerTool, Description("Echoes the input message back, useful for testing connectivity.")]
    public static string Echo(
        [Description("The message to echo back")] string message) =>
        $"Echo: {message}";

    [McpServerTool, Description("Adds two numbers and returns the result.")]
    public static string Add(
        [Description("First number")] double a,
        [Description("Second number")] double b) =>
        $"Result: {a + b}";
}

using ModelContextProtocol.Server;
using System.ComponentModel;
using System.Text.Json;

[McpServerResourceType]
public static class Resources
{
    [McpServerResource(UriTemplate = "config://app", Name = "App Config",
        MimeType = "application/json"),
     Description("Returns the current application configuration as JSON.")]
    public static string GetAppConfig() =>
        JsonSerializer.Serialize(new
        {
            AppName = "McpHttpServer",
            Version = "1.0.0",
            Environment = Environment.GetEnvironmentVariable("ASPNETCORE_ENVIRONMENT") ?? "Production",
            MaxConnections = 100,
            Features = new { Logging = true, Caching = false }
        }, new JsonSerializerOptions { WriteIndented = true });

    [McpServerResource(UriTemplate = "info://server", Name = "Server Info",
        MimeType = "text/plain"),
     Description("Returns basic server runtime information.")]
    public static string GetServerInfo() =>
        $"Runtime: {System.Runtime.InteropServices.RuntimeInformation.FrameworkDescription}, " +
        $"OS: {System.Runtime.InteropServices.RuntimeInformation.OSDescription}, " +
        $"Started: {DateTime.UtcNow:O}";
}

